```javascript
// Select all checkboxes
const checkboxes = document.querySelectorAll('input[type="checkbox"]');

// Loop through each checkbox and check it
checkboxes.forEach(checkbox => {
    checkbox.checked = true;
});

// Now, if you have a save button with an id of "saveButton", you can add an event listener to it
document.getElementById('saveButton').addEventListener('click', function() {
    // All checkboxes are now checked, so you can proceed to save them
    console.log("All checkboxes are checked and ready to be saved!");
});
